# Run Once for Each Item — clean a user record
def title_case(s: str) -> str:
    return ' '.join(w.capitalize() for w in s.split())

def normalize_email(e: str) -> str:
    return e.strip().lower()

data = _json
return {
    'json': {
        'full_name': title_case(data['name']),
        'email': normalize_email(data['email']),
        'age': int(data['age']),
        'is_adult': int(data['age']) >= 18
    }
}

# Validate and split valid vs invalid records
items = _input.all()

valid = []
errors = []

for item in items:
    data = item.json
    try:
        num = int(data['value'])
        if num < 0:
            raise ValueError('negative not allowed')
        valid.append({'json': {'id': data['id'], 'number': num}})
    except (ValueError, KeyError) as e:
        errors.append({'json': {
            'id': data.get('id'),
            'error': str(e),
            'raw': data
        }})

# Return both — downstream can use IF node to route
return valid + errors

# Raising an error stops the workflow (or triggers Error workflow)
